'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Test } from '@/lib/types';

type MenuLevel = 'color' | 'nombre' | 'main' | 'category';
type ColorOption = 'green' | 'white' | 'yellow' | 'cyan' | 'red' | 'magenta';

const colorMap: Record<ColorOption, string> = {
  green: 'text-green-300',
  white: 'text-white',
  yellow: 'text-yellow-300',
  cyan: 'text-cyan-300',
  red: 'text-red-300',
  magenta: 'text-magenta-300',
};

const colorNames: ColorOption[] = ['green', 'white', 'yellow', 'cyan', 'red', 'magenta'];

export default function TestSelector() {
  const router = useRouter();
  const [tests, setTests] = useState<Test[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [userName, setUserName] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [level, setLevel] = useState<MenuLevel>('color');
  const [currentCategory, setCurrentCategory] = useState<string>('');
  const [selectedColor, setSelectedColor] = useState<ColorOption>('green');

  const categories = [
    { id: 'BaseDatos', name: 'BBDD' },
    { id: 'Programación/Teoría', name: 'Java2' },
    { id: 'Programación/EACs', name: 'EACs Java2' },
  ];

  useEffect(() => {
    fetchTests();
  }, []);

  async function fetchTests() {
    try {
      const response = await fetch('/api/tests');
      const result = await response.json();
      if (result.success) {
        setTests(result.tests);
      } else {
        setError('Error al cargar tests');
      }
    } catch (err) {
      setError('Error al conectar con el servidor');
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  const getTestsInCategory = (catId: string) => {
    return tests.filter((t) => t.category === catId);
  };

  const currentTests = getTestsInCategory(currentCategory);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (level === 'color') {
        if (e.key === 'ArrowDown') {
          e.preventDefault();
          setSelectedIndex((prev) => (prev + 1) % colorNames.length);
        } else if (e.key === 'ArrowUp') {
          e.preventDefault();
          setSelectedIndex((prev) => (prev - 1 + colorNames.length) % colorNames.length);
        } else if (e.key === 'Enter') {
          setSelectedColor(colorNames[selectedIndex]);
          localStorage.setItem('terminalColor', colorNames[selectedIndex]);
          setLevel('nombre');
          setSelectedIndex(0);
        }
      } else if (level === 'nombre') {
        if (e.key === 'Enter') {
          if (userName.trim()) {
            setLevel('main');
            setSelectedIndex(0);
          }
        }
      } else if (level === 'main') {
        if (e.key === 'ArrowDown') {
          e.preventDefault();
          setSelectedIndex((prev) => (prev + 1) % categories.length);
        } else if (e.key === 'ArrowUp') {
          e.preventDefault();
          setSelectedIndex((prev) => (prev - 1 + categories.length) % categories.length);
        } else if (e.key === 'Enter') {
          setCurrentCategory(categories[selectedIndex].id);
          setLevel('category');
          setSelectedIndex(0);
        }
      } else if (level === 'category') {
        if (e.key === 'ArrowDown') {
          e.preventDefault();
          setSelectedIndex((prev) => (prev + 1) % (currentTests.length + 1));
        } else if (e.key === 'ArrowUp') {
          e.preventDefault();
          setSelectedIndex((prev) => (prev - 1 + currentTests.length + 1) % (currentTests.length + 1));
        } else if (e.key === 'Enter') {
          if (selectedIndex < currentTests.length) {
            router.push(`/tests/${currentTests[selectedIndex].id}?userName=${encodeURIComponent(userName)}`);
          } else {
            setLevel('main');
            setSelectedIndex(0);
          }
        } else if (e.key === 'Escape') {
          setLevel('main');
          setSelectedIndex(0);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [level, selectedIndex, categories, currentTests, userName, currentCategory]);

  if (loading) {
    return (
      <div className="min-h-screen bg-black p-4 font-mono text-sm text-green-300 flex items-center justify-center">
        <div>$ cargando tests...</div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen bg-black p-4 font-mono text-sm ${colorMap[selectedColor]}`}>
      <div className="max-w-2xl mx-auto">
        <div className="mb-1">$ java -jar tests.jar</div>
        <div className={`mb-4 ${selectedColor === 'green' ? 'text-green-500' : selectedColor === 'white' ? 'text-gray-400' : selectedColor === 'yellow' ? 'text-yellow-500' : selectedColor === 'cyan' ? 'text-cyan-500' : selectedColor === 'red' ? 'text-red-500' : 'text-magenta-500'}`}>TESTS JAVA v1.0</div>

        {level === 'color' && (
          <>
            <div className="mb-3">selecciona color de fuente:</div>
            <div className="space-y-1 mb-3 ml-2">
              {colorNames.map((color, idx) => (
                <div
                  key={color}
                  className={`${selectedIndex === idx ? `${colorMap[color]} bg-opacity-20 bg-white` : colorMap[color]}`}
                >
                  {selectedIndex === idx ? '> ' : '  '}{color.toUpperCase()}
                </div>
              ))}
            </div>
          </>
        )}

        {level === 'nombre' && (
          <>
            <div className="mb-2">nombre: <input
              autoFocus
              type="text"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              className="bg-black text-green-300 outline-none border-b border-green-300 ml-1"
            /></div>
            <div className="text-yellow-600 text-xs">&gt; presiona ENTER</div>
          </>
        )}

        {level === 'main' && (
          <>
            <div className="mb-3">usuario: {userName}</div>
            <div className="mb-2 text-green-500">[ CATEGORIAS ]</div>
            <div className="space-y-1 mb-3 ml-2">
              {categories.map((cat, idx) => (
                <div key={cat.id} className={selectedIndex === idx ? 'bg-green-300 text-black' : ''}>
                  {selectedIndex === idx ? '> ' : '  '}{cat.name}
                </div>
              ))}
            </div>
          </>
        )}

        {level === 'category' && (
          <>
            <div className="mb-2 text-green-500">[ {categories.find(c => c.id === currentCategory)?.name} ]</div>
            <div className="space-y-1 mb-3 ml-2">
              {currentTests.map((test, idx) => (
                <div key={test.id} className={selectedIndex === idx ? 'bg-green-300 text-black' : ''}>
                  {selectedIndex === idx ? '> ' : '  '}{test.name}
                </div>
              ))}
              <div className={selectedIndex === currentTests.length ? 'bg-green-300 text-black' : ''}>
                {selectedIndex === currentTests.length ? '> ' : '  '}[ATRAS]
              </div>
            </div>
          </>
        )}

        {error && <div className="text-red-500 mt-2">{error}</div>}
      </div>
    </div>
  );
}
